async (params, browser) => {
  // Open Kaggle unified search
  await browser.open(`https://www.kaggle.com/search?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('a[href*=\'/datasets/\'], a[href*=\'/competitions/\'], a[href*=\'/code/\'], a[href*=\'/models/\'], ul[role=\'list\']', 15000)

  // Let results render
  await browser.wait(3000)

  // Scroll for more results
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const seen = new Set(); document.querySelectorAll('a[href]').forEach(a => { const href = a.getAttribute('href') || ''; if (seen.has(href) || !href.startsWith('/')) return; const isDataset = href.match(/^\/datasets\/[^/]+\/[^/]+/); const isComp = href.match(/^\/competitions\/[^/]+$/); const isCode = href.match(/^\/code\/[^/]+\/[^/]+/); const isModel = href.match(/^\/models\/[^/]+\/[^/]+/); if (!isDataset && !isComp && !isCode && !isModel) return; const title = a.textContent.trim(); if (!title || title.length > 200 || title.length < 3) return; seen.add(href); let type = 'unknown'; if (isDataset) type = 'dataset'; else if (isComp) type = 'competition'; else if (isCode) type = 'notebook'; else if (isModel) type = 'model'; const parent = a.closest('li') || a.parentElement; const desc = parent ? Array.from(parent.querySelectorAll('span,p')).map(e => e.textContent.trim()).filter(t => t.length > 20 && t !== title).slice(0, 1).join('') : ''; results.push({ title: title.substring(0, 200), url: 'https://www.kaggle.com' + href, type, description: desc.substring(0, 300) }); }); return { query: '' + params.query + '', result_count: results.length, results: results.slice(0, 20) };`)

  return search_results
}
